function shuffleOptions(q) {
    const opts = [...q.options];
    const correctText = opts[q.correctAnswer];
    // Fisher-Yates shuffle
    for (let i = opts.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [opts[i], opts[j]] = [opts[j], opts[i]];
    }
    return { ...q, options: opts, correctAnswer: opts.indexOf(correctText) };
}

async function deleteExisting() {
    const snap = await db.collection('questions').where('examId', '==', PGMP_ID).get();
    if (snap.empty) { console.log('No existing PgMP questions to delete.'); return; }
    const batchSize = 500;
    const docs = snap.docs;
    for (let i = 0; i < docs.length; i += batchSize) {
        const batch = db.batch();
        docs.slice(i, i + batchSize).forEach(d => batch.delete(d.ref));
        await batch.commit();
    }
    console.log(`Deleted ${docs.length} existing PgMP questions.`);
}

(async () => {
    await deleteExisting();
    const shuffled = questions.map(shuffleOptions);
    // Firestore batch limit is 500; 170 questions fits in one batch
    const batch = db.batch();
    for (const q of shuffled) {
        const ref = db.collection('questions').doc();
        batch.set(ref, q);
    }
    await batch.commit();
    console.log(`Seeded ${shuffled.length} PgMP questions (options shuffled)`);
    process.exit(0);
})().catch(e => { console.error(e); process.exit(1); });
